@startuml
participant "ListingController" as LC #D3E5F8#041C2B;
participant "FixPriceListingMapper\n<font color=red>interface</font>" as FPLM #FFEBEE#7A0906 {
  readList() : ArrayList&lt;<i><color=#ffebef>?</color></i>&gt;;\n--\ncreate(title:String,...) :\n<i><color=#ffebef>?</color></i>;
}
database Database <<Database>>{ }
LC -> FPLM:readList();
activate FPLM;
note right of FPLM:<b>FIXED_PRICE_LISTING TABLE:</b>\ntitle VARCHAR(25)\ndescription TEXT;\ncategory_id INT NOT NULL,\nseller_email VARCHAR(25);\nbuyer_email VARCHAR(25); \npayment_method ENUM('cash','card');\nprice DECIMAL(10,2));
alt <u>If table exists in DB.</u>: then 
    note over Databases:"SELECT * FROM fixed_price_listing";
else else if "<u>No such Table Exists!</u>";then  
   create object Fix_Price_Listing_Table AS fplt from class Fixed_Price_Listings_table ;   
end alt    
deactivate FPLM;
@enduml
